                                            "type": "array",
                                            "items": {
                                                "type": "object",
                                                "required": ["name", "type"],
                                                "properties": {
                                                    "name": {"type": "string"},
                                                    "type": {
                                                        "type": "string",
                                                        "enum": ["person", "organization", "location"],
                                                    },
                                                },
                                            },
