}


# ─── Test Cases ───────────────────────────────────────────────────────────────

def run_tests():
    print("=" * 70)
    print("specllm REAL LLM INTEGRATION TEST")
    print("=" * 70)

    provider = AnthropicProvider()
    app = SpecLLM(spec=SPEC, provider=provider)
    client = app.test_client()

    results = {"passed": 0, "failed": 0, "errors": []}

    def assert_test(name, condition, detail=""):
        if condition:
            results["passed"] += 1
            print(f"  ✅ {name}")
        else:
            results["failed"] += 1
            results["errors"].append(f"{name}: {detail}")
            print(f"  ❌ {name}: {detail}")

    # ─── TEST 1: Basic ticket routing ─────────────────────────────────────────
    print("\n─── TEST 1: Basic ticket routing (happy path) ───")
    resp = client.post("/v1/route-ticket", json_body={
        "title": "Payment failed on checkout",
        "body": "I tried to pay with my credit card but got error code E-5021",
        "customer_tier": "pro",
    })
    print(f"  Response: {json.dumps(resp, indent=2)}")

