    errs = validate_schema({"team": "billing", "priority": 3, "tags": [1, 2, 3]}, schema)
    assert_test("Validator: non-string array items caught", len(errs) > 0)

    # ─── Summary ──────────────────────────────────────────────────────────────
    print("\n" + "=" * 70)
    print(f"RESULTS: {results['passed']} passed, {results['failed']} failed")
    print(f"LLM calls: {provider.call_count} | Tokens: {provider.total_tokens}")
