    # ─── Known Issues / Faults Found ─────────────────────────────────────────
    print("\n─── KNOWN ISSUES / FAULTS FOUND ───")
    issues = []

    # Check: prompt decorator API mismatch
    # README shows @app.prompt("/v1/moderate") with ONE arg, but code takes TWO
    issues.append(
        "API MISMATCH: README shows @app.prompt(path) but code requires @app.prompt(path, method). "
        "The decorator signature in __init__.py is `prompt(self, path, method)` but README example only passes path."
    )

    # Check: provider.call() return type handling
    # If LLM returns non-JSON, the pipeline has no handling for it.
    # The retry handler expects call_fn to return a dict, but if JSON parsing fails
    # in our provider, we return a dict with __raw_text__. The validator will fail
    # on this, triggering a retry - but the feedback won't tell the LLM "respond with JSON".
    issues.append(
        "NON-JSON HANDLING: If the LLM returns non-JSON text, the provider must handle parsing. "
        "The framework has no built-in JSON extraction/recovery layer between provider.call() and validation. "
        "The system prompt instructing JSON-only output is entirely the provider's responsibility."
    )

    # Check: input enum validation gap
    # The validator validates enum if the field is present, but only if the schema
    # for that field is being validated (i.e., if it's in 'properties' and present in data)
    issues.append(
        "INPUT ENUM VALIDATION: The validator DOES validate enum on non-required fields if they're present. "
        "But the error message doesn't clearly indicate which enum values are valid."
    )

    # Check: cache key doesn't include provider/model
    issues.append(
        "CACHE KEY: Cache key is based on (path, method, body) but NOT the provider/model. "
        "If you switch providers, stale cached responses from a different model could be served."
    )

    # Check: no timeout handling
    issues.append(
        "NO TIMEOUT: RequestPipeline has no timeout on LLM calls. A slow provider will block indefinitely. "
        "The errors/codes.py defines PROVIDER_TIMEOUT but it's never raised anywhere."
    )

    # Check: TestClient doesn't set status codes
    issues.append(
        "TESTCLIENT: TestClient._request() returns raw dict but no HTTP status code. "
        "You can't distinguish a 400 from a 422 from a 503 when using test_client(). "
        "The server properly maps error codes to HTTP status, but TestClient loses this info."
    )

    # Check: from_openapi provider parameter type ambiguity
    issues.append(
        "PROVIDER TYPE: from_openapi(provider=...) accepts string ('anthropic') per README but __init__ "
        "expects an LLMProvider instance. There's no provider registry/factory to resolve string names."
    )

    # Check: contract_test doesn't actually validate output schema
    issues.append(
        "CONTRACT_TEST: contract_test() calls runner.run() but ContractTestRunner doesn't validate "
        "that the LLM response matches the endpoint's response_schema. It just calls the provider."
    )

    for i, issue in enumerate(issues, 1):
        print(f"  {i}. {issue}")

    return results["failed"] == 0


if __name__ == "__main__":
    try:
        success = run_tests()
        sys.exit(0 if success else 1)
    except Exception as e:
        print(f"\n💥 FATAL ERROR: {e}")
        traceback.print_exc()
        sys.exit(2)

