"""
Integration test for specllm using a real LLM (Anthropic Claude) as the provider.

This script wires up Claude as the provider, sends real requests through the
full specllm pipeline, and validates that structured output actually works
end-to-end. It surfaces real faults in the framework.

Usage:
    export ANTHROPIC_API_KEY="your-key-here"
    python test_integration_real_llm.py
"""
import json
import os
import sys
import time
import traceback

# Add parent to path for imports
sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))

from specllm import SpecLLM
from specllm.llm.providers import LLMProvider


class AnthropicProvider(LLMProvider):
    """Real Anthropic Claude provider for integration testing."""

    def __init__(self, model: str = "claude-sonnet-4-20250514"):
        self.model = model
        self.api_key = os.environ.get("ANTHROPIC_API_KEY")
        if not self.api_key:
            raise RuntimeError("Set ANTHROPIC_API_KEY environment variable")
        self.call_count = 0
        self.total_tokens = 0

    def call(self, prompt: str, system_prompt: str = None) -> dict:
        """Call Anthropic API and return parsed JSON."""
        import urllib.request
        import urllib.error

        self.call_count += 1

        system = system_prompt or (
            "You are a backend API. Respond ONLY with valid JSON matching the schema described. "
            "No markdown, no code fences, no explanation. Just the JSON object."
        )

        payload = {
            "model": self.model,
            "max_tokens": 1024,
            "system": system,
            "messages": [{"role": "user", "content": prompt}],
        }

        data = json.dumps(payload).encode("utf-8")
        req = urllib.request.Request(
            "https://api.anthropic.com/v1/messages",
            data=data,
            headers={
                "Content-Type": "application/json",
                "x-api-key": self.api_key,
                "anthropic-version": "2023-06-01",
            },
        )

        try:
            with urllib.request.urlopen(req, timeout=30) as resp:
                body = json.loads(resp.read().decode("utf-8"))
        except urllib.error.HTTPError as e:
            error_body = e.read().decode("utf-8") if e.fp else ""
            raise RuntimeError(f"Anthropic API error {e.code}: {error_body}")

        # Extract text content
        text = ""
        for block in body.get("content", []):
            if block.get("type") == "text":
                text += block["text"]

        self.total_tokens += body.get("usage", {}).get("input_tokens", 0)
        self.total_tokens += body.get("usage", {}).get("output_tokens", 0)

        # Parse JSON from response - strip markdown fences if present
        text = text.strip()
        if text.startswith("```"):
            lines = text.split("\n")
            lines = lines[1:]  # remove opening fence
            if lines and lines[-1].strip() == "```":
                lines = lines[:-1]
            text = "\n".join(lines).strip()

        try:
            return json.loads(text)
        except json.JSONDecodeError as e:
            # Return raw text so retry logic can kick in with feedback
            print(f"  [WARN] LLM returned non-JSON: {text[:100]}...")
            return {"__raw_text__": text, "__parse_error__": str(e)}


