    print("\n─── TEST 7: Caching behavior ───")
    call_count_before = provider.call_count
    resp1 = client.post("/v1/classify-sentiment", json_body={
        "text": "This is terrible and I hate it."
    })
    calls_for_first = provider.call_count - call_count_before

    call_count_before = provider.call_count
    resp2 = client.post("/v1/classify-sentiment", json_body={
        "text": "This is terrible and I hate it."
    })
    calls_for_second = provider.call_count - call_count_before

    print(f"  First request: {calls_for_first} LLM call(s)")
    print(f"  Second request (cached): {calls_for_second} LLM call(s)")
    assert_test("Second call uses cache (0 LLM calls)", calls_for_second == 0, f"got {calls_for_second} calls")
    assert_test("Cached response matches", resp1 == resp2, f"resp1={resp1}, resp2={resp2}")
    assert_test("Cache metadata set", app._pipeline.last_metadata.get("cache_hit") is True)

    # ─── TEST 8: Retry behavior with adversarial schema ───────────────────────
    # This tests if the retry/validation loop can recover when LLM returns
    # a response that doesn't match (e.g., wrong type for a field).
    # We use the existing endpoints which have strict schemas.
    print("\n─── TEST 8: Edge case - empty input text ───")
    resp = client.post("/v1/classify-sentiment", json_body={"text": ""})
    print(f"  Response: {json.dumps(resp, indent=2)}")
    # With empty text, LLM should still return valid schema
    assert_test("Returns valid response for empty text", "error" not in resp or resp.get("error", {}).get("code") != "OUTPUT_SCHEMA_VIOLATION")

    # ─── TEST 9: Test the prompt decorator ────────────────────────────────────
    print("\n─── TEST 9: Custom prompt decorator ───")
    # NOTE: The prompt decorator API in __init__.py takes (path, method) but
    # the README shows @app.prompt("/v1/moderate") with only path.
    # This is a potential API inconsistency bug.
    @app.prompt("/v1/classify-sentiment", "post")
    def custom_sentiment_prompt(body):
        return (
            f"Classify this text as positive/negative/neutral with confidence 0-1.\n"
            f"Text: {body['text']}\n"
            f"Respond with JSON: {{\"sentiment\": \"...\", \"confidence\": 0.XX}}"
        )

    # Clear cache to force re-evaluation
    app._pipeline.cache._store.clear()

    resp = client.post("/v1/classify-sentiment", json_body={
        "text": "The weather is nice today."
    })
    print(f"  Response: {json.dumps(resp, indent=2)}")
    assert_test("Custom prompt works", "error" not in resp)
    assert_test("Still returns valid schema", "sentiment" in resp and "confidence" in resp)

    # ─── TEST 10: Stress test - check schema validation catches bad LLM output ─
    print("\n─── TEST 10: Validation robustness (non-JSON response handling) ───")
    # We can test this by checking what happens if the provider returns garbage.
    # Since we're using a real LLM, let's instead verify the validator itself
    from specllm.spec.validator import validate_schema
    schema = SPEC["paths"]["/v1/route-ticket"]["post"]["responses"]["200"]["content"]["application/json"]["schema"]

    # Valid
    errs = validate_schema({"team": "billing", "priority": 3, "tags": ["payment"]}, schema)
    assert_test("Validator: valid response passes", len(errs) == 0, f"errors: {errs}")

    # Missing required
    errs = validate_schema({"team": "billing"}, schema)
    assert_test("Validator: missing 'priority' caught", len(errs) > 0)

    # Wrong type
    errs = validate_schema({"team": "billing", "priority": "high"}, schema)
    assert_test("Validator: string instead of int caught", len(errs) > 0)

    # Out of range
    errs = validate_schema({"team": "billing", "priority": 10}, schema)
    assert_test("Validator: priority > 5 caught", len(errs) > 0)

    # Wrong array item type
    errs = validate_schema({"team": "billing", "priority": 3, "tags": [1, 2, 3]}, schema)
    assert_test("Validator: non-string array items caught", len(errs) > 0)

    # ─── Summary ──────────────────────────────────────────────────────────────
    print("\n" + "=" * 70)
    print(f"RESULTS: {results['passed']} passed, {results['failed']} failed")
    print(f"LLM calls: {provider.call_count} | Tokens: {provider.total_tokens}")
    print("=" * 70)

    if results["errors"]:
        print("\nFAILURES:")
        for err in results["errors"]:
            print(f"  • {err}")

    # ─── Known Issues / Faults Found ─────────────────────────────────────────
    print("\n─── KNOWN ISSUES / FAULTS FOUND ───")
    issues = []

    # Check: prompt decorator API mismatch
    # README shows @app.prompt("/v1/moderate") with ONE arg, but code takes TWO
    issues.append(
        "API MISMATCH: README shows @app.prompt(path) but code requires @app.prompt(path, method). "
        "The decorator signature in __init__.py is `prompt(self, path, method)` but README example only passes path."
    )

    # Check: provider.call() return type handling
    # If LLM returns non-JSON, the pipeline has no handling for it.
    # The retry handler expects call_fn to return a dict, but if JSON parsing fails
    # in our provider, we return a dict with __raw_text__. The validator will fail
    # on this, triggering a retry - but the feedback won't tell the LLM "respond with JSON".
    issues.append(
        "NON-JSON HANDLING: If the LLM returns non-JSON text, the provider must handle parsing. "
        "The framework has no built-in JSON extraction/recovery layer between provider.call() and validation. "
        "The system prompt instructing JSON-only output is entirely the provider's responsibility."
    )

    # Check: input enum validation gap
    # The validator validates enum if the field is present, but only if the schema
    # for that field is being validated (i.e., if it's in 'properties' and present in data)
    issues.append(
        "INPUT ENUM VALIDATION: The validator DOES validate enum on non-required fields if they're present. "
        "But the error message doesn't clearly indicate which enum values are valid."
    )

    # Check: cache key doesn't include provider/model
    issues.append(
        "CACHE KEY: Cache key is based on (path, method, body) but NOT the provider/model. "
        "If you switch providers, stale cached responses from a different model could be served."
    )

    # Check: no timeout handling
    issues.append(
        "NO TIMEOUT: RequestPipeline has no timeout on LLM calls. A slow provider will block indefinitely. "
        "The errors/codes.py defines PROVIDER_TIMEOUT but it's never raised anywhere."
    )

    # Check: TestClient doesn't set status codes
    issues.append(
        "TESTCLIENT: TestClient._request() returns raw dict but no HTTP status code. "
        "You can't distinguish a 400 from a 422 from a 503 when using test_client(). "
        "The server properly maps error codes to HTTP status, but TestClient loses this info."
    )

    # Check: from_openapi provider parameter type ambiguity
    issues.append(
        "PROVIDER TYPE: from_openapi(provider=...) accepts string ('anthropic') per README but __init__ "
        "expects an LLMProvider instance. There's no provider registry/factory to resolve string names."
    )

    # Check: contract_test doesn't actually validate output schema
    issues.append(
        "CONTRACT_TEST: contract_test() calls runner.run() but ContractTestRunner doesn't validate "
        "that the LLM response matches the endpoint's response_schema. It just calls the provider."
    )

    for i, issue in enumerate(issues, 1):
        print(f"  {i}. {issue}")

    return results["failed"] == 0


if __name__ == "__main__":
    try:
        success = run_tests()
        sys.exit(0 if success else 1)
    except Exception as e:
        print(f"\n💥 FATAL ERROR: {e}")
        traceback.print_exc()
        sys.exit(2)

